import { Link } from "react-router-dom";

import EventList from "../components/EventsList";

function EventsPage() {

    

  return (
    <>
      <h1>EventsPage</h1>
      {DUMMY_EVENTS.map((event) => (
        <ul key={event.id}>
          <li>
            <Link to={`/events/${event.id}`}>{event.title}</Link>
          </li>
        </ul>
      ))}
    </>
  );
}

export default EventsPage;
